search:NestJS + Kafka Streams:nestjs kaf.content:
- **CLI Commands**:
  - `nest new project-name --package-manager npm`
  - `npm install @nestjs/kafka`

- **Latest Versions**:
  - NestJS: v9.x
  - Kafka: 3.x

- **Key Config Options**:
  - `bootstrapModule` in `main.ts`
    ```typescript
    import { NestFactory } from '@nestjs/core';
    import { AppModule } from './app.module';

    async function bootstrap() {
      const app = await NestFactory.create(AppModule);
      await app.listen(3000);
    }
    bootstrap();
    ```
  - `KafkaOptions` in `kafka.config.ts`
    ```typescript
    import { KafkaOptions, Transport } from '@nestjs/microservices';

    export const kafkaConfig: KafkaOptions = {
      transport: Transport.KAFKA,
      options: {
        client: {
          brokers: ['localhost:9092'],
        },
        consumer: {
          groupId: 'test-group',
        },
      },
    };
    ```
  - `Consumer` and `Producer` in `kafka.service.ts`
    ```typescript
    import { Injectable } from '@nestjs/common';
    import { ClientKafka, Transport } from '@nestjs/microservices';

    @Injectable()
    export class KafkaService {
      private readonly client: ClientKafka;

      constructor() {
        this.client = new ClientKafka({
          transport: Transport.KAFKA,
          options: {
            client: {
              brokers: ['localhost:9092'],
            },
            consumer: {
              groupId: 'test-group',
            },
          },
        });
        this.client.connect();
      }

      async consume() {
        await this.client.subscribeToResponseOf('test-topic');
        await this.client.send({ topic: 'test-topic', payload: 'Hello World' }).subscribe({
          next(msg) {
            console.log(`Received message: ${msg}`);
          },
          error(err) {
            console.error(`Error: ${err}`);
          },
        });
      }
    }
    ```
